import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote — base premiums", () => {
    it.todo("empty item list yields premium of 5 G (processing fee only)");
    it.todo("a single sword yields premium 105 G (100 base + 5 fee)");
    it.todo("a single amulet yields premium 65 G (60 base + 5 fee)");
    it.todo("a single staff yields premium 85 G (80 base + 5 fee)");
    it.todo("a single potion yields premium 45 G (40 base + 5 fee)");
    it.todo("a sword and an amulet yields premium 165 G (100 + 60 + 5)");
  });

  describe("quote — components and blocks", () => {
    it.todo("a single rune yields premium 30 G (25 base + 5 fee)");
    it.todo("two runes yield premium 55 G (50 base + 5 fee)");
    it.todo("three runes yield premium 65 G (60 block + 5 fee)");
    it.todo("four runes yield premium 105 G (100 base + 5 fee, no block)");
    it.todo("seven runes yield premium 180 G (175 base + 5 fee)");
    it.todo("two runes + one moonstone yield premium 80 G (75 base + 5 fee)");
    it.todo("three runes + three moonstones yield premium 125 G (120 base + 5 fee)");
  });

  describe("quote — item-specific modifiers", () => {
    it.todo("a cursed sword adds 50% surcharge on the cursed item only");
    it.todo("a sword with enchantment 5 adds 30% high-enchantment surcharge");
    it.todo("a sword with enchantment 4 adds no high-enchantment surcharge");
    it.todo("a cursed sword with enchantment 5 adds both surcharges");
    it.todo("cursed surcharge on multi-item policy applies to cursed item only");
  });

  describe("quote — policy-wide modifiers", () => {
    it.todo("loyalty discount of 20% applies for customer with 2+ years");
    it.todo("first insurance surcharge of 10% applies on first quote");
    it.todo("follow-up contract discount of 15% applies on second+ quote");
  });

  describe("quote — rounding", () => {
    it.todo("premium is rounded up in MHPCO's favor");
  });

  describe("quote — integration examples", () => {
    it.todo("newcomer with cursed sword yields premium 165 G");
    it.todo("long-standing customer's second contract with cursed enchanted sword yields 160 G");
  });

  describe("quote — validation", () => {
    it.todo("unknown item type causes an error");
  });

  describe("claim — basic payouts", () => {
    it.todo("standard sword damage of 500 G yields payout 400 G (minus 100 deductible)");
    it.todo("rune damage of 200 G yields payout 100 G (minus 100 deductible)");
    it.todo("damage to multiple items applies deductible per item");
  });

  describe("claim — special clauses", () => {
    it.todo("dragon-material sword fully reimbursed minus deductible");
    it.todo("enchantment 8 sword reimbursed at 50% then deductible");
    it.todo("enchantment 9 dragon sword: 50% rule wins, then deductible");
  });

  describe("claim — cap and remaining", () => {
    it.todo("payout capped at twice insurance sum (cap exhaustion)");
    it.todo("remainingCap is reported correctly after a claim");
  });

  describe("claim — rounding", () => {
    it.todo("payout is rounded down in MHPCO's favor");
  });

  describe("claim — validation", () => {
    it.todo("damage referencing item not in policy causes error");
    it.todo("negative damage amount causes error");
    it.todo("more damages of a type than insured causes error");
  });
});

