    });
    it("a single sword yields premium 105 G (100 base + 5 fee)", () => {
      expect(
        quote(
          { yearsWithMHPCO: 0 },
          [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
          0,
        ),
      ).toBe(105);
    });
    it("a single amulet yields premium 65 G (60 base + 5 fee)", () => {
      expect(
        quote(
          { yearsWithMHPCO: 0 },
          [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
          0,
        ),
      ).toBe(65);
    });
    it.todo("a single staff yields premium 85 G (80 base + 5 fee)");
    it.todo("a single potion yields premium 45 G (40 base + 5 fee)");
    it.todo("a sword and an amulet yields premium 165 G (100 + 60 + 5)");
  });

  describe("quote — components and blocks", () => {
    it.todo("a single rune yields premium 30 G (25 base + 5 fee)");
    it.todo("two runes yield premium 55 G (50 base + 5 fee)");
    it.todo("three runes yield premium 65 G (60 block + 5 fee)");
    it.todo("four runes yield premium 105 G (100 base + 5 fee, no block)");
    it.todo("seven runes yield premium 180 G (175 base + 5 fee)");
    it.todo("two runes + one moonstone yield premium 80 G (75 base + 5 fee)");
    it.todo("three runes + three moonstones yield premium 125 G (120 base + 5 fee)");
  });

  describe("quote — item-specific modifiers", () => {
    it.todo("a cursed sword adds 50% surcharge on the cursed item only");
    it.todo("a sword with enchantment 5 adds 30% high-enchantment surcharge");
    it.todo("a sword with enchantment 4 adds no high-enchantment surcharge");
    it.todo("a cursed sword with enchantment 5 adds both surcharges");
    it.todo("cursed surcharge on multi-item policy applies to cursed item only");
  });

