export type Customer = { yearsWithMHPCO: number };
export type Item = { type: string };
export type Incident = unknown;

const PROCESSING_FEE = 5;

const BASE_PRICES: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE = 60;

const basePriceFor = (item: Item): number => BASE_PRICES[item.type] ?? 0;

const runePremiumFor = (runeCount: number): number =>
  runeCount === RUNE_BLOCK_SIZE
    ? RUNE_BLOCK_PRICE
    : runeCount * BASE_PRICES.rune;

export const quote = (
  _customer: Customer,
  items: Item[],
  _previousQuoteCount: number,
): number => {
  const runes = items.filter((i) => i.type === "rune");
  const nonRunes = items.filter((i) => i.type !== "rune");
  const nonRunePremium = nonRunes.reduce(
    (sum, item) => sum + basePriceFor(item),
    0,
  );
  return nonRunePremium + runePremiumFor(runes.length) + PROCESSING_FEE;
};

export const claim = (
  _customer: Customer,
  _items: Item[],
  _incident: Incident,
  _capUsed: number,
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

