export type Customer = { yearsWithMHPCO: number };
export type Item = { type: string };
export type Incident = unknown;

const PROCESSING_FEE = 5;

const BASE_PRICES: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = ["rune", "moonstone"];
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const basePriceFor = (type: string): number => BASE_PRICES[type] ?? 0;

const isComponentType = (type: string): boolean =>
  COMPONENT_TYPES.includes(type);

const countOfType = (items: Item[], type: string): number =>
  items.filter((i) => i.type === type).length;

const basePremiumForType = (items: Item[], type: string): number => {
  const count = countOfType(items, type);
  if (isComponentType(type) && count === BLOCK_SIZE) return BLOCK_PRICE;
  return count * basePriceFor(type);
};

export const quote = (
  _customer: Customer,
  items: Item[],
  _previousQuoteCount: number,
): number => {
  const types = Object.keys(BASE_PRICES);
  const basePremium = types.reduce(
    (sum, type) => sum + basePremiumForType(items, type),
    0,
  );
  return basePremium + PROCESSING_FEE;
};

export const claim = (
  _customer: Customer,
  _items: Item[],
  _incident: Incident,
  _capUsed: number,
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

