  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = ["rune", "moonstone"];
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const basePriceFor = (type: string): number => BASE_PRICES[type] ?? 0;

const isComponentType = (type: string): boolean =>
  COMPONENT_TYPES.includes(type);

const itemModifiedPremium = (item: Item): number => {
  const base = basePriceFor(item.type);
  return item.cursed ? base * 1.5 : base;
};

const groupByType = (items: Item[]): Map<string, Item[]> =>
  items.reduce((groups, item) => {
    const group = groups.get(item.type) ?? [];
    return groups.set(item.type, [...group, item]);
  }, new Map<string, Item[]>());

const premiumForGroup = (type: string, group: Item[]): number => {
  if (isComponentType(type) && group.length === BLOCK_SIZE) return BLOCK_PRICE;
  return group.reduce((sum, item) => sum + itemModifiedPremium(item), 0);
};

export const quote = (
  _customer: Customer,
  items: Item[],
  _previousQuoteCount: number,
): number => {
  const groups = groupByType(items);
  const basePremium = Array.from(groups).reduce(
    (sum, [type, group]) => sum + premiumForGroup(type, group),
    0,
  );
  return basePremium + PROCESSING_FEE;
};

export const claim = (
  _customer: Customer,
  _items: Item[],
  _incident: Incident,
  _capUsed: number,
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

